<?php namespace App\Repositories\Student;use App\Repositories\BaseRepository;use App\Models\Student\StudentTransfer;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class StudentTransferRepository extends BaseRepository{    public function __construct(StudentTransfer $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('transfer_date', [$startDate, $endDate])->get();    }    public function getApprovedTransfers(): Collection    {        return $this->query()->where('status', 'approved')->get();    }    public function getPendingTransfers(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function getByFromSchool(int $schoolId): Collection    {        return $this->findByField('from_school_id', $schoolId);    }    public function getByToSchool(int $schoolId): Collection    {        return $this->findByField('to_school_id', $schoolId);    }    public function transfer(int $studentId, array $data): StudentTransfer    {        $data['student_id'] = $studentId;        return $this->create($data);    }}